mapper.update:
		UPDATE ORG_MNFCT_MST  /* MnfctMgmtMapper.updateMnfctMgmt */
		SET 
            MNFCT_NM = #{mnfctNm, jdbcType=VARCHAR} 
           , BIZ_REG_NUM = #{bizRegNum, jdbcType=VARCHAR} 
           , RPRSEN_NM = #{rprsenNm, jdbcType=VARCHAR} 
           , ZIPCD = #{zipcd, jdbcType=VARCHAR} 
           , ADDR = #{addr, jdbcType=VARCHAR} 
           , DTL_ADDR = #{dtlAddr, jdbcType=VARCHAR} 
           , RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
           , RVISN_DTTM = SYSDATE
           , MNFCT_YN = #{mnfctYn, jdbcType=VARCHAR} 
           , TELNUM = #{telnum, jdbcType=VARCHAR} 
           , FAX = #{fax, jdbcType=VARCHAR} 
           , EMAIL = #{email, jdbcType=VARCHAR} 
           , SERIALNO_FLG = #{serialnoFlg, jdbcType=VARCHAR} 
        WHERE MNFCT_ID = #{mnfctId}
